CREATE TABLE IF NOT EXISTS supervision_wecom_webhook (id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(128) NOT NULL,webhook_cipher TEXT NOT NULL,status TINYINT NOT NULL DEFAULT 1,last_tested_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS supervision_message_template (id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(128) NOT NULL,channel VARCHAR(32) NOT NULL,message_type VARCHAR(32) NOT NULL,content_json JSON NOT NULL,status TINYINT NOT NULL DEFAULT 1,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS supervision_task_recipient (id BIGINT PRIMARY KEY AUTO_INCREMENT,task_id BIGINT NOT NULL,recipient_type VARCHAR(32) NOT NULL,recipient_ref VARCHAR(128) NOT NULL,mention_mode VARCHAR(32) NULL,INDEX idx_recipient_task(task_id));
CREATE TABLE IF NOT EXISTS supervision_message_delivery (id BIGINT PRIMARY KEY AUTO_INCREMENT,task_id BIGINT NULL,execution_id BIGINT NULL,channel VARCHAR(32) NOT NULL,target_snapshot JSON NULL,message_type VARCHAR(32) NOT NULL,idempotency_key VARCHAR(128) NOT NULL,request_batch VARCHAR(64) NULL,wecom_errcode INT NULL,status VARCHAR(32) NOT NULL,failure_reason VARCHAR(1024) NULL,retry_count INT NOT NULL DEFAULT 0,sent_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_delivery_idempotency(idempotency_key));
INSERT IGNORE INTO supervision_wecom_webhook(id,name,webhook_cipher,status,created_at) SELECT id,name,webhook_url,1,created_at FROM supervision_wechat_robot;